function solve(grid, x, y, k) {
    // Create a deep copy of the grid to avoid modifying the original during processing
    const newGrid = grid.map(row => [...row]);

    // Iterate over each row in the submatrix to be flipped
    for (let i = 0; i < k; i++) {
        const originalRow = x + i;
        const flippedRow = x + k - 1 - i;

        // Only flip if the originalRow is different from flippedRow to avoid unnecessary operations
        if (originalRow < flippedRow) {
            // Swap the relevant portions of the rows
            for (let j = y; j < y + k; j++) {
                const temp = newGrid[originalRow][j];
                newGrid[originalRow][j] = newGrid[flippedRow][j];
                newGrid[flippedRow][j] = temp;
            }
        }
    }

    return newGrid;
}
